// ============================================================================
// ANSI escape sequence constants for Unicode board rendering.
// ============================================================================
//
// These are the SGR (Select Graphic Rendition) sequences used by
// `format_board_state_as_unicode_ansi`. They are kept as named
// constants so the color scheme can be retuned without hunting
// through the render loop.
//
// Color scheme (initial; tune as needed):
//   - White pieces: bright-white foreground (\x1b[97m)
//   - Black pieces: yellow foreground (\x1b[33m)
//   - Light squares: bright-black ("gray") background (\x1b[100m)
//   - Dark squares: no background color set
//   - Empty squares: middle-dot glyph, no foreground color override
//
// Per project policy these are byte-slice literals so we can write
// them via `write_bytes_to_buffer` without UTF-8 conversion at the
// call site (they are pure ASCII).

/// ANSI: reset all attributes (color, background, intensity).
const ANSI_SGR_RESET: &[u8] = b"\x1b[0m";

/// ANSI: set foreground to bright white. Used for White's pieces.
const ANSI_SGR_FOREGROUND_BRIGHT_WHITE: &[u8] = b"\x1b[97m";

/// ANSI: set foreground to yellow. Used for Black's pieces.
const ANSI_SGR_FOREGROUND_YELLOW: &[u8] = b"\x1b[33m";

/// ANSI: set background to bright black (gray). Used for light squares.
const ANSI_SGR_BACKGROUND_LIGHT_SQUARE: &[u8] = b"\x1b[100m";

// ============================================================================
// Unicode chess glyphs as UTF-8 byte sequences.
// ============================================================================
//
// Each Unicode chess piece is encoded in three bytes in UTF-8. We
// hard-code the byte sequences rather than relying on string
// literal conversion so the renderer never touches the str type
// (Buffy compatibility) and the byte cost is auditable.
//
// Reference (U+2654 through U+265F):
//   ♔ U+2654 White King   -> E2 99 94
//   ♕ U+2655 White Queen  -> E2 99 95
//   ♖ U+2656 White Rook   -> E2 99 96
//   ♗ U+2657 White Bishop -> E2 99 97
//   ♘ U+2658 White Knight -> E2 99 98
//   ♙ U+2659 White Pawn   -> E2 99 99
//   ♚ U+265A Black King   -> E2 99 9A
//   ♛ U+265B Black Queen  -> E2 99 9B
//   ♜ U+265C Black Rook   -> E2 99 9C
//   ♝ U+265D Black Bishop -> E2 99 9D
//   ♞ U+265E Black Knight -> E2 99 9E
//   ♟ U+265F Black Pawn   -> E2 99 9F
//   · U+00B7 Middle Dot   -> C2 B7

const UNICODE_GLYPH_WHITE_KING: &[u8] = &[0xE2, 0x99, 0x94];
const UNICODE_GLYPH_WHITE_QUEEN: &[u8] = &[0xE2, 0x99, 0x95];
const UNICODE_GLYPH_WHITE_ROOK: &[u8] = &[0xE2, 0x99, 0x96];
const UNICODE_GLYPH_WHITE_BISHOP: &[u8] = &[0xE2, 0x99, 0x97];
const UNICODE_GLYPH_WHITE_KNIGHT: &[u8] = &[0xE2, 0x99, 0x98];
const UNICODE_GLYPH_WHITE_PAWN: &[u8] = &[0xE2, 0x99, 0x99];
const UNICODE_GLYPH_BLACK_KING: &[u8] = &[0xE2, 0x99, 0x9A];
const UNICODE_GLYPH_BLACK_QUEEN: &[u8] = &[0xE2, 0x99, 0x9B];
const UNICODE_GLYPH_BLACK_ROOK: &[u8] = &[0xE2, 0x99, 0x9C];
const UNICODE_GLYPH_BLACK_BISHOP: &[u8] = &[0xE2, 0x99, 0x9D];
const UNICODE_GLYPH_BLACK_KNIGHT: &[u8] = &[0xE2, 0x99, 0x9E];
const UNICODE_GLYPH_BLACK_PAWN: &[u8] = &[0xE2, 0x99, 0x9F];
const UNICODE_GLYPH_EMPTY_SQUARE: &[u8] = &[0xC2, 0xB7];

/// Return the UTF-8 byte sequence for the given piece's Unicode chess glyph.
///
/// ## Project Context
///
/// Companion to `ascii_character_for_piece` for the Unicode-ANSI
/// renderer. Returns a `'static` byte slice so the caller writes
/// the bytes directly into its output buffer with no allocation.
///
/// ## Memory & Panic Policy
///
/// No heap. No panics. Total branch coverage of `PieceKind` x
/// `PieceColor`.
fn unicode_bytes_for_piece(piece_value: Piece) -> &'static [u8] {
    match (piece_value.piece_color, piece_value.piece_kind) {
        (PieceColor::White, PieceKind::King) => UNICODE_GLYPH_WHITE_KING,
        (PieceColor::White, PieceKind::Queen) => UNICODE_GLYPH_WHITE_QUEEN,
        (PieceColor::White, PieceKind::Rook) => UNICODE_GLYPH_WHITE_ROOK,
        (PieceColor::White, PieceKind::Bishop) => UNICODE_GLYPH_WHITE_BISHOP,
        (PieceColor::White, PieceKind::Knight) => UNICODE_GLYPH_WHITE_KNIGHT,
        (PieceColor::White, PieceKind::Pawn) => UNICODE_GLYPH_WHITE_PAWN,
        (PieceColor::Black, PieceKind::King) => UNICODE_GLYPH_BLACK_KING,
        (PieceColor::Black, PieceKind::Queen) => UNICODE_GLYPH_BLACK_QUEEN,
        (PieceColor::Black, PieceKind::Rook) => UNICODE_GLYPH_BLACK_ROOK,
        (PieceColor::Black, PieceKind::Bishop) => UNICODE_GLYPH_BLACK_BISHOP,
        (PieceColor::Black, PieceKind::Knight) => UNICODE_GLYPH_BLACK_KNIGHT,
        (PieceColor::Black, PieceKind::Pawn) => UNICODE_GLYPH_BLACK_PAWN,
    }
}

/// Renders the given `BoardState` as Unicode chess symbols with ANSI
/// color codes into the provided buffer.
///
/// ## Piece encoding
///
/// White pieces: ♔ ♕ ♖ ♗ ♘ ♙  rendered with ANSI bright-white foreground.
/// Black pieces: ♚ ♛ ♜ ♝ ♞ ♟  rendered with ANSI yellow foreground.
/// Empty squares: · (U+00B7 MIDDLE DOT), no color code.
///
/// ## Square shading
///
/// Light squares (where `file + rank` is odd, with a1 = file 0, rank 0
/// being a dark square per standard chess convention) receive an ANSI
/// bright-black ("gray") background. Dark squares receive no
/// background SGR. This was chosen to keep dark squares as the
/// terminal default and only paint the light squares.
///
/// ## Output format
///
/// Identical grid layout to `format_board_state_as_ascii`:
/// rank labels on the left, file labels on the bottom. Each piece
/// glyph (or empty-square dot) is bracketed by ANSI SGR sequences
/// for color and background, followed by an SGR reset.
///
/// ## Buffer sizing
///
/// Per-square worst-case byte cost:
///   background-on (6) + foreground (5) + glyph (3) + reset (4) +
///   trailing space (1) = 19 bytes.
/// Board grid total: 64 * 19 = 1216 bytes.
/// Rank labels, newlines, and the file-label footer add ~100 bytes.
/// Recommended `TUI_BOARD_RENDER_BUFFER_BYTES` for this renderer:
/// 2048 bytes. The constant must be raised from its current 256
/// before this function is wired into the TUI; otherwise the
/// renderer returns `Err(InternalIndexOutOfBounds)` and the TUI
/// shows its fallback message ("(board render error)").
///
/// ## Arguments
///
/// - `state`: the board state to render.
/// - `render_from_white_view`: if true, rank 8 is at the top (White
///   orientation). If false, the board is flipped (Black view).
/// - `output_buffer`: caller-provided stack buffer. No allocation.
///
/// ## Returns
///
/// On success, `Ok(bytes_written)`. On insufficient buffer space,
/// `Err(MoveValidationError::InternalIndexOutOfBounds)`.
///
/// ## Memory & Panic Policy
///
/// No heap. No panics. All writes go through `write_byte_to_buffer`
/// and `write_bytes_to_buffer`, which bounds-check on every write.
pub fn format_board_state_as_unicode_ansi(
    state: &BoardState,
    render_from_white_view: bool,
    output_buffer: &mut [u8],
) -> Result<usize, MoveValidationError> {
    let mut write_position: usize = 0;

    // Iterate ranks in display order. White view: rank 7 first.
    // Black view: rank 0 first. Bounded loop, no recursion.
    let mut rank_iteration_step: u8 = 0;
    while rank_iteration_step < BOARD_RANK_COUNT {
        let actual_rank_index: u8 = if render_from_white_view {
            BOARD_RANK_COUNT - 1 - rank_iteration_step
        } else {
            rank_iteration_step
        };

        // Rank label: leading space, digit, two spaces.
        write_position = write_byte_to_buffer(output_buffer, write_position, b' ')?;
        let rank_label_byte: u8 = b'1' + actual_rank_index;
        write_position = write_byte_to_buffer(output_buffer, write_position, rank_label_byte)?;
        write_position = write_byte_to_buffer(output_buffer, write_position, b' ')?;
        write_position = write_byte_to_buffer(output_buffer, write_position, b' ')?;

        // Iterate files left to right in display order.
        let mut file_iteration_step: u8 = 0;
        while file_iteration_step < BOARD_FILE_COUNT {
            let actual_file_index: u8 = if render_from_white_view {
                file_iteration_step
            } else {
                BOARD_FILE_COUNT - 1 - file_iteration_step
            };

            let square_index =
                square_index_from_file_and_rank(actual_file_index, actual_rank_index)?;
            let square_contents = state.board_squares[square_index as usize];

            // Light squares: (file + rank) odd. a1 (0,0) is dark.
            let square_is_light: bool =
                (actual_file_index as u16 + actual_rank_index as u16) % 2 == 1;

            // ----- Emit background SGR for light squares only.
            if square_is_light {
                write_position = write_bytes_to_buffer(
                    output_buffer,
                    write_position,
                    ANSI_SGR_BACKGROUND_LIGHT_SQUARE,
                )?;
            }

            // ----- Emit foreground SGR (for pieces only; empty squares
            //       use whatever foreground is currently active, which
            //       is the terminal default since we reset after each
            //       square).
            match square_contents {
                Some(piece_here) => {
                    let foreground_bytes: &[u8] = match piece_here.piece_color {
                        PieceColor::White => ANSI_SGR_FOREGROUND_BRIGHT_WHITE,
                        PieceColor::Black => ANSI_SGR_FOREGROUND_YELLOW,
                    };
                    write_position =
                        write_bytes_to_buffer(output_buffer, write_position, foreground_bytes)?;

                    let glyph_bytes = unicode_bytes_for_piece(piece_here);
                    write_position =
                        write_bytes_to_buffer(output_buffer, write_position, glyph_bytes)?;
                }
                None => {
                    write_position = write_bytes_to_buffer(
                        output_buffer,
                        write_position,
                        UNICODE_GLYPH_EMPTY_SQUARE,
                    )?;
                }
            }

            // ----- Always reset SGR after each square so background and
            //       foreground do not leak into the trailing separator
            //       space or the next square. This costs 4 bytes per
            //       square but keeps state explicit and auditable.
            write_position = write_bytes_to_buffer(output_buffer, write_position, ANSI_SGR_RESET)?;

            // Separating space after each square.
            write_position = write_byte_to_buffer(output_buffer, write_position, b' ')?;

            file_iteration_step += 1;
        }

        // End of rank: newline.
        write_position = write_byte_to_buffer(output_buffer, write_position, b'\n')?;
        rank_iteration_step += 1;
    }

    // Blank line and file labels (uncolored, ASCII only).
    write_position = write_byte_to_buffer(output_buffer, write_position, b'\n')?;
    write_position = write_bytes_to_buffer(output_buffer, write_position, b"    ")?;

    let mut file_label_step: u8 = 0;
    while file_label_step < BOARD_FILE_COUNT {
        let actual_file_index: u8 = if render_from_white_view {
            file_label_step
        } else {
            BOARD_FILE_COUNT - 1 - file_label_step
        };
        let file_label_byte: u8 = b'a' + actual_file_index;
        write_position = write_byte_to_buffer(output_buffer, write_position, file_label_byte)?;
        write_position = write_byte_to_buffer(output_buffer, write_position, b' ')?;
        file_label_step += 1;
    }
    write_position = write_byte_to_buffer(output_buffer, write_position, b'\n')?;

    Ok(write_position)
}

/// Compose the current dungeon-master state into a sequence of
/// content lines and emit them, in order, through the supplied
/// `emit_line` closure.
///
/// ## Project Context
///
/// Called once per refresh cycle by the outer wrapper (Section 64).
/// In production the wrapper passes a closure that writes each line
/// to the terminal via Buffy and appends the same line to the
/// game-log file. In tests the closure captures emitted lines for
/// assertion.
///
/// ## Side effects
///
/// Writes the ANSI clear-screen sequence directly to the terminal
/// via Buffy at the start of each frame. This is NOT routed through
/// `emit_line`, so the log file receives content lines only.
///
/// On Buffy write failure (unlikely; the terminal sink is typically
/// always-writable), the clear-screen sequence is silently dropped.
/// The rest of the frame still emits.
///
/// ## Arguments
///
/// - `state`: the dungeon-master state to render.
/// - `current_unix_timestamp`: the wall-clock moment for the frame,
///   used by the clock-line formatters. Per project policy the
///   wrapper samples this once per tick and passes it in.
/// - `emit_line`: closure invoked once per content line. The slice
///   passed to the closure has no trailing newline; the closure is
///   free to add one if its destination (terminal, log file)
///   requires it.
///
/// ## Rendering mode
///
/// The board is rendered in ASCII or Unicode+ANSI depending on
/// `state.config.tui_render_mode`. All other output (status lines,
/// clock lines) is unaffected by this setting.
///
/// ## Memory & Panic Policy
///
/// No heap inside this function. No panics. The board scratch
/// buffer (`TUI_BOARD_RENDER_BUFFER_BYTES` = 256 bytes) and per-line
/// buffer (`TUI_LINE_BUFFER_BYTES` = 96 bytes) are stack resident.
pub fn write_dungeon_master_state_to_tui_and_log(
    state: &DungeonMasterState,
    current_unix_timestamp: u64,
    emit_line: &mut dyn FnMut(&[u8]),
) {
    // ----- Step 1: clear the terminal screen directly (not via emit_line).
    // The clear-screen sequence is a terminal control operation, not
    // content; it must not appear in the log file.
    let _ = buffy_print(
        "{}",
        &[BuffyFormatArg::Str(
            core::str::from_utf8(ANSI_CLEAR_SCREEN_AND_HOME).unwrap_or(""),
        )],
    );

    // ----- Step 2: render board into a stack buffer, then emit per line.
    // The rendering function is selected by tui_render_mode. Both
    // functions share the same signature and write into the same buffer,
    // so the rest of this function is identical for both modes.
    let mut board_render_buffer: [u8; TUI_BOARD_RENDER_BUFFER_BYTES] =
        [0u8; TUI_BOARD_RENDER_BUFFER_BYTES];

    let render_from_white_view: bool = should_render_from_white_view(&state.config);

    let board_render_result: Result<usize, MoveValidationError> = match state.config.tui_render_mode
    {
        TuiRenderMode::Ascii => format_board_state_as_ascii(
            &state.board,
            render_from_white_view,
            &mut board_render_buffer,
        ),
        TuiRenderMode::UnicodeAnsi => format_board_state_as_unicode_ansi(
            &state.board,
            render_from_white_view,
            &mut board_render_buffer,
        ),
    };

    match board_render_result {
        Ok(board_byte_length) => {
            emit_board_lines_from_rendered_buffer(
                &board_render_buffer,
                board_byte_length,
                emit_line,
            );
        }
        Err(_) => {
            // Defensive: both render functions only fail on
            // buffer-too-small, which is unreachable given the chosen
            // TUI_BOARD_RENDER_BUFFER_BYTES sizing. Emit a visible
            // placeholder so the user sees something rather than a
            // silent gap.
            emit_line(b"(board render error)");
        }
    }

    // ----- Step 3: emit the six status block lines.
    // These are mode-independent: clock values and status text are
    // plain ASCII regardless of tui_render_mode.
    emit_one_formatted_line(
        |output_buffer| write_status_line_into_buffer(state, output_buffer),
        emit_line,
    );

    emit_one_formatted_line(
        |output_buffer| write_whole_move_is_next_line_into_buffer(state, output_buffer),
        emit_line,
    );

    emit_one_formatted_line(
        |output_buffer| write_move_number_line_into_buffer(state, output_buffer),
        emit_line,
    );

    emit_one_formatted_line(
        |output_buffer| {
            write_clock_line_into_buffer(
                state,
                PieceColor::White,
                current_unix_timestamp,
                output_buffer,
            )
        },
        emit_line,
    );

    emit_one_formatted_line(
        |output_buffer| {
            write_clock_line_into_buffer(
                state,
                PieceColor::Black,
                current_unix_timestamp,
                output_buffer,
            )
        },
        emit_line,
    );

    emit_one_formatted_line(
        |output_buffer| {
            write_total_time_line_into_buffer(state, current_unix_timestamp, output_buffer)
        },
        emit_line,
    );
}

// ============================================================================
// SECTION 62: Cargo Tests
// ============================================================================

#[cfg(test)]
mod section_62_write_dungeon_master_state_to_tui_and_log_tests {
    use super::*;

    /// Helper: build a `MemochessGameConfig` for use in renderer tests.
    fn build_test_config_for_renderer(
        local_user_name: &[u8],
        white_player_name: &[u8],
        black_player_name: &[u8],
    ) -> MemochessGameConfig {
        MemochessGameConfig::try_construct_memochess_game_config(
            b"/tmp/memo_chess_test_games",
            b"/tmp/memo_chess_test_chrono",
            b"/tmp/memo_chess_test_logs",
            local_user_name,
            white_player_name,
            black_player_name,
            600, // 10-minute per-player budget
            10,
            50,
            1_000_000_000, // bootstrap_run_unix_timestamp_seconds,
            TuiRenderMode::Ascii,
        )
        .expect("test config must construct")
    }

    /// Helper: capture emitted lines into a Vec<Vec<u8>> using a
    /// closure. Test-only heap use, per project policy that tests
    /// may allocate.
    fn capture_emitted_lines<F>(invoke_renderer: F) -> Vec<Vec<u8>>
    where
        F: FnOnce(&mut dyn FnMut(&[u8])),
    {
        let mut captured_lines: Vec<Vec<u8>> = Vec::new();
        let mut emit_line_closure = |line_bytes: &[u8]| {
            captured_lines.push(line_bytes.to_vec());
        };
        invoke_renderer(&mut emit_line_closure);
        captured_lines
    }

    #[test]
    fn initial_state_emits_seventeen_content_lines() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let state = create_initial_dungeon_master_state(config);

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 1_000_000_000, emit_line);
        });

        // 8 board ranks + 1 blank line + 1 file-label line + 6 status block lines = 16
        // OR with optional trailing blank in board format = 17.
        // The board format produced by format_board_state_as_ascii is
        // stable; we assert the structure is "reasonably-sized non-empty
        // line set" rather than coupling to an exact count that the
        // board renderer could legitimately adjust.
        assert!(
            captured.len() >= 14,
            "expected at least 14 lines emitted, got {}",
            captured.len()
        );
    }

    #[test]
    fn initial_state_status_line_says_playing() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let state = create_initial_dungeon_master_state(config);

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let status_line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: playing");
        assert!(
            status_line_present,
            "expected a 'Status: playing' line to be emitted"
        );
    }

    #[test]
    fn initial_state_current_move_says_white() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let state = create_initial_dungeon_master_state(config);

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Whose turn is next: White");
        assert!(line_present);
    }

    #[test]
    fn initial_state_move_number_is_one() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let state = create_initial_dungeon_master_state(config);

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Current move-pair: 1");
        assert!(line_present);
    }

    #[test]
    fn initial_state_white_clock_at_full_budget() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let state = create_initial_dungeon_master_state(config);

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        // 600 seconds = "0:10:00"; budget also 600 seconds. Both halves
        // of the clock line should be "0:10:00".
        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"White Time: 0:10:00 / 0:10:00");
        assert!(
            line_present,
            "expected 'White Time: 0:10:00 / 0:10:00' in emitted lines"
        );
    }

    #[test]
    fn initial_state_total_time_zero() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let state = create_initial_dungeon_master_state(config);

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Total Time: 0:00:00");
        assert!(line_present);
    }

    #[test]
    fn checkmate_white_wins_status_line_correct() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let mut state = create_initial_dungeon_master_state(config);
        state.board.game_status = GameStatus::CheckmateWhitewin;

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: Checkmate. White wins.");
        assert!(line_present);
    }

    #[test]
    fn black_resigned_status_line_correct() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let mut state = create_initial_dungeon_master_state(config);
        state.board.game_status = GameStatus::BlackResigned;

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: Black resigned. White wins.");
        assert!(line_present);
    }

    #[test]
    fn white_timeflagged_status_line_correct() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let mut state = create_initial_dungeon_master_state(config);
        state.board.game_status = GameStatus::WhitecheeseTimeflagged;

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: White flagged. Black wins.");
        assert!(line_present);
    }

    #[test]
    fn black_stalemated_status_line_correct() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let mut state = create_initial_dungeon_master_state(config);
        state.board.game_status = GameStatus::BlackStalemated;

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: Stalemate. Black is stalemated (cannot move)");
        assert!(line_present);
    }

    #[test]
    fn draw_n_move_rule_status_line_includes_configured_n_value() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let mut state = create_initial_dungeon_master_state(config);
        state.board.game_status = GameStatus::DrawForcedNmoveRule;
        // The default config has n_move_rule = 50 per build_test_config_for_renderer.

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: Draw due to 50-move-rule");
        assert!(
            line_present,
            "expected 'Status: Draw due to 50-move-rule' in emitted lines"
        );
    }

    #[test]
    fn draw_by_repetition_status_line_correct() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let mut state = create_initial_dungeon_master_state(config);
        state.board.game_status = GameStatus::DrawByRepetition;

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: Draw due to repetition");
        assert!(line_present);
    }

    #[test]
    fn draw_agreed_status_line_correct() {
        let config = build_test_config_for_renderer(b"tom", b"alice", b"bob");
        let mut state = create_initial_dungeon_master_state(config);
        state.board.game_status = GameStatus::DrawAgreed;

        let captured = capture_emitted_lines(|emit_line| {
            write_dungeon_master_state_to_tui_and_log(&state, 0, emit_line);
        });

        let line_present = captured
            .iter()
            .any(|line| line.as_slice() == b"Status: Draw: Players agree to Draw.");
        assert!(line_present);
    }

    #[test]
    fn view_orientation_white_for_white_player_local_user() {
        let config = build_test_config_for_renderer(b"alice", b"alice", b"bob");
        // local_user_name == white_player_name, so view should be White's.
        let from_white = should_render_from_white_view(&config);
        assert!(from_white);
    }

    #[test]
    fn view_orientation_black_for_black_player_local_user() {
        let config = build_test_config_for_renderer(b"bob", b"alice", b"bob");
        // local_user_name == black_player_name, so view should be Black's.
        let from_white = should_render_from_white_view(&config);
        assert!(!from_white);
    }

    #[test]
    fn view_orientation_white_for_spectator_local_user() {
        let config = build_test_config_for_renderer(b"carol", b"alice", b"bob");
        // local_user_name matches neither player; default to White's view.
        let from_white = should_render_from_white_view(&config);
        assert!(from_white);
    }
}

// ============================================================================
// SECTION 63: Game-Log Writer and Terminal-Write Helper
// ============================================================================
//
// ## Project Context
//
// This section provides the two destinations of the double-publish
// closure that the wrapper (Section 64) will pass to
// `write_dungeon_master_state_to_tui_and_log` (Section 62):
//
//   1. Terminal destination: write one content line to stdout via
//      Buffy, with newline. Implemented by
//      `write_one_line_to_terminal_via_buffy_best_effort`.
//
//   2. Log destination: open the game-log file in append mode,
//      write one content line followed by `\n`, close. Implemented
//      by `append_one_line_to_game_log_file_best_effort`. Mirrors
//      the open-append-close pattern of
//      `append_skip_event_to_log_file_best_effort` (Section 57).
//
// Both functions are best-effort: any I/O failure is silently
// dropped, the game continues, and `DungeonMasterState` is never
// touched. The double-publish is non-essential observability; a
// dropped line is preferable to a halted game.
//
// ## Filename convention
//
// The game-log filename is
//   `chess_game_log_<bootstrap_run_unix_timestamp>.txt`
// produced by `build_game_log_filename_into_buffer`. The infix is
// the bootstrap-run Unix timestamp captured at
// `q_and_a_setup_bootstrap` entry and carried through
// `MemochessGameConfig.bootstrap_run_unix_timestamp_seconds`. This
// matches the bootstrap error-log filename pattern from Section 57
// so both files from one run share the same infix.
//
// ## What this section does NOT do
//
// - Does not format any content. Content lines arrive as `&[u8]`
//   from Section 62.
// - Does not append metadata, timestamps, or severity levels to
//   per-line output. The line written to the log is byte-identical
//   to the line written to the terminal, plus a single trailing `\n`.
// - Does not hold a file handle between calls. Each call opens,
//   appends, closes.
// - Does not create the log directory. The bootstrap layer ensures
//   the directory exists (see `ensure_logging_directory_exists_best_effort`
//   in Section 59).

// ----------------------------------------------------------------------------
// Section 63 Constants
// ----------------------------------------------------------------------------

/// Filename prefix for game-log files.
///
/// The complete filename is
///   `<prefix><bootstrap_run_unix_timestamp_decimal><suffix>`
/// where the timestamp is filled in by the filename builder.
pub const GAME_LOG_FILENAME_PREFIX: &[u8] = b"chess_game_log_";

/// Filename suffix (extension) for game-log files.
pub const GAME_LOG_FILENAME_SUFFIX: &[u8] = b".txt";

/// Stack-buffer size for assembling a game-log filename.
///
/// Sized to accommodate prefix (15 bytes) + maximum `u64` decimal
/// representation (20 bytes) + suffix (4 bytes) = 39 bytes, rounded
/// up to 48 for headroom and alignment.
pub const MAX_GAME_LOG_FILENAME_BYTES: usize = 48;

// ----------------------------------------------------------------------------
// Internal helper: write u64 as decimal ASCII into a buffer
// ----------------------------------------------------------------------------

/// Write the decimal ASCII representation of `value` into the front
/// of `output_buffer`. Returns the byte length written, or `None`
/// if the buffer is too small.
///
/// This is a local copy of the same helper used by Section 57's
/// filename builder. The duplication is deliberate: each section's
/// filename builder owns its own copy so neither section depends on
/// an internal helper from the other, and future changes to one
/// builder's number-formatting policy do not affect the other.
fn write_u64_decimal_into_game_log_filename_buffer(
    value: u64,
    output_buffer: &mut [u8],
) -> Option<usize> {
    // u64::MAX is 18_446_744_073_709_551_615: at most 20 ASCII digits.
    let mut digit_scratch_buffer: [u8; 20] = [0; 20];
    let mut digit_count: usize = 0;
    let mut remaining_value: u64 = value;

    if remaining_value == 0 {
        digit_scratch_buffer[0] = b'0';
        digit_count = 1;
    } else {
        while remaining_value > 0 && digit_count < digit_scratch_buffer.len() {
            digit_scratch_buffer[digit_count] = b'0' + (remaining_value % 10) as u8;
            remaining_value /= 10;
            digit_count += 1;
        }
    }

    if digit_count > output_buffer.len() {
        return None;
    }

    // Reverse the digits into the output buffer (digits were
    // produced least-significant first).
    let mut output_index = 0_usize;
    while output_index < digit_count {
        output_buffer[output_index] = digit_scratch_buffer[digit_count - 1 - output_index];
        output_index += 1;
    }

    Some(digit_count)
}

// ----------------------------------------------------------------------------
// Game-log filename builder
// ----------------------------------------------------------------------------

/// Assemble the game-log filename
/// `chess_game_log_<unix_timestamp_decimal>.txt` into the supplied
/// stack buffer.
///
/// ## Arguments
///
/// - `bootstrap_run_unix_timestamp_seconds`: the timestamp infix.
///   Taken from `MemochessGameConfig.bootstrap_run_unix_timestamp_seconds`
///   by the wrapper.
/// - `output_buffer`: a writable byte buffer with capacity at least
///   `MAX_GAME_LOG_FILENAME_BYTES`.
///
/// ## Returns
///
/// `Some(filename_byte_length)` on success.
/// `None` if `output_buffer` is too small to hold prefix + timestamp
/// + suffix.
///
/// ## Memory & Panic Policy
///
/// No heap. No panics. Stack-only.
pub fn build_game_log_filename_into_buffer(
    bootstrap_run_unix_timestamp_seconds: u64,
    output_buffer: &mut [u8],
) -> Option<usize> {
    let mut current_write_position: usize = 0;

    // Write the prefix.
    let prefix_byte_length = GAME_LOG_FILENAME_PREFIX.len();
    if current_write_position + prefix_byte_length > output_buffer.len() {
        return None;
    }
    let mut copy_index = 0_usize;
    while copy_index < prefix_byte_length {
        output_buffer[current_write_position + copy_index] = GAME_LOG_FILENAME_PREFIX[copy_index];
        copy_index += 1;
    }
    current_write_position += prefix_byte_length;

    // Write the timestamp infix.
    let timestamp_byte_length = write_u64_decimal_into_game_log_filename_buffer(
        bootstrap_run_unix_timestamp_seconds,
        &mut output_buffer[current_write_position..],
    )?;
    current_write_position += timestamp_byte_length;

    // Write the suffix.
    let suffix_byte_length = GAME_LOG_FILENAME_SUFFIX.len();
    if current_write_position + suffix_byte_length > output_buffer.len() {
        return None;
    }
    let mut copy_index = 0_usize;
    while copy_index < suffix_byte_length {
        output_buffer[current_write_position + copy_index] = GAME_LOG_FILENAME_SUFFIX[copy_index];
        copy_index += 1;
    }
    current_write_position += suffix_byte_length;

    Some(current_write_position)
}

// ----------------------------------------------------------------------------
// Terminal-write helper (best effort)
// ----------------------------------------------------------------------------

/// Write one content line to the terminal via Buffy, followed by a
/// newline.
///
/// ## Project Context
///
/// Used by the wrapper's double-publish closure as the terminal
/// half. The line content is whatever
/// `write_dungeon_master_state_to_tui_and_log` (Section 62) emits;
/// the terminator (`\n`) is added here so that Section 62 itself
/// emits no trailing newlines.
///
/// ## Best-effort semantics
///
/// Buffy's `buffy_println` returns `io::Result<()>`. Failure paths
/// (e.g., stdout is closed, terminal is unreachable) are silently
/// dropped. The game continues.
///
/// ## Arguments
///
/// - `line_bytes`: the line content. May contain any ASCII or
///   UTF-8 bytes. Non-UTF-8 sequences are written via a fallback
///   path that emits a defensive placeholder, since `buffy_println`
///   requires `&str`.
///
/// ## Memory & Panic Policy
///
/// No heap. No panics. Buffy is stack-only.
pub fn write_one_line_to_terminal_via_buffy_best_effort(line_bytes: &[u8]) {
    // Buffy requires &str; attempt UTF-8 conversion.
    match core::str::from_utf8(line_bytes) {
        Ok(line_as_str) => {
            // Format string "{}" plus the line as a single Str arg.
            // Discarding the io::Result per best-effort semantics.
            let _ = buffy_println("{}", &[BuffyFormatArg::Str(line_as_str)]);
        }
        Err(_) => {
            // Defensive fallback. The renderer in Section 62 produces
            // ASCII-only output (ANSI escape sequences plus board
            // characters plus status text), so this branch is
            // unreachable in normal operation. Emit a visible marker
            // so a future change that introduces non-UTF-8 bytes
            // produces an observable artifact rather than a silent
            // dropped line.
            let _ = buffy_println("(non-utf8 line)", &[]);
        }
    }
}

// ----------------------------------------------------------------------------
// Game-log append helper (best effort)
// ----------------------------------------------------------------------------

/// Append one content line to the game-log file, followed by `\n`.
///
/// ## Project Context
///
/// Used by the wrapper's double-publish closure as the log half.
/// Each call opens the log file in append mode, writes
/// `line_bytes` + `\n`, and closes the file. No handle is held
/// between calls.
///
/// ## Best-effort semantics
///
/// Any I/O failure (filename overflow, directory missing, open
/// fails, write fails) is silently dropped. The game continues.
/// This mirrors Section 57's
/// `append_skip_event_to_log_file_best_effort`.
///
/// POSIX guarantees `O_APPEND` writes are atomic at the file-system
/// level for the short lines this function produces (typically
/// under 100 bytes), so no locking is needed.
///
/// ## Arguments
///
/// - `memo_chess_log_directory_path`: the directory in which the
///   log file lives. Must already exist; this function does NOT
///   create it. (Directory creation is the bootstrap layer's
///   responsibility per Section 59.)
/// - `bootstrap_run_unix_timestamp_seconds`: the filename infix,
///   taken from `state.config.bootstrap_run_unix_timestamp_seconds()`.
/// - `line_bytes`: the content line to append. The newline is
///   added by this function; do not include a trailing newline
///   in `line_bytes`.
///
/// ## Memory & Panic Policy
///
/// No panics. Heap touch: one bounded `PathBuf::join` per call,
/// freed before return (same pattern as Section 57). Stack: one
/// `MAX_GAME_LOG_FILENAME_BYTES` filename buffer.
pub fn append_one_line_to_game_log_file_best_effort(
    memo_chess_log_directory_path: &Path,
    bootstrap_run_unix_timestamp_seconds: u64,
    line_bytes: &[u8],
) {
    // Step 1: assemble the filename into a stack buffer.
    let mut filename_buffer: [u8; MAX_GAME_LOG_FILENAME_BYTES] = [0; MAX_GAME_LOG_FILENAME_BYTES];
    let filename_byte_length = match build_game_log_filename_into_buffer(
        bootstrap_run_unix_timestamp_seconds,
        &mut filename_buffer,
    ) {
        Some(length_value) => length_value,
        None => {
            return;
        }
    };

    // Step 2: convert the filename bytes to a &str for join.
    let filename_str = match core::str::from_utf8(&filename_buffer[..filename_byte_length]) {
        Ok(s) => s,
        Err(_) => {
            // Unreachable: the filename builder writes ASCII only.
            return;
        }
    };

    // Step 3: build the absolute path. PathBuf::join allocates;
    // bounded by MAX_GAME_LOG_FILENAME_BYTES + directory_path.len(),
    // and freed before return.
    let absolute_log_file_path = memo_chess_log_directory_path.join(filename_str);

    // Step 4: open in append mode, create if absent.
    let mut file_handle = match OpenOptions::new()
        .append(true)
        .create(true)
        .open(&absolute_log_file_path)
    {
        Ok(handle_value) => handle_value,
        Err(_) => {
            return;
        }
    };

    // Step 5: write line_bytes followed by a single newline. Either
    // write may fail (e.g., disk full); both failures are dropped.
    if file_handle.write_all(line_bytes).is_err() {
        return;
    }
    let _ = file_handle.write_all(b"\n");
}

// ============================================================================
// SECTION 63: Cargo Tests
// ============================================================================

#[cfg(test)]
mod section_63_game_log_writer_tests {
    use super::*;

    // -- Filename builder tests --

    #[test]
    fn game_log_filename_for_zero_timestamp() {
        let mut buffer: [u8; MAX_GAME_LOG_FILENAME_BYTES] = [0; MAX_GAME_LOG_FILENAME_BYTES];
        let length_written = build_game_log_filename_into_buffer(0, &mut buffer)
            .expect("zero timestamp must produce a filename");
        assert_eq!(&buffer[..length_written], b"chess_game_log_0.txt");
    }

    #[test]
    fn game_log_filename_for_typical_timestamp() {
        let mut buffer: [u8; MAX_GAME_LOG_FILENAME_BYTES] = [0; MAX_GAME_LOG_FILENAME_BYTES];
        let length_written = build_game_log_filename_into_buffer(1_778_532_301, &mut buffer)
            .expect("typical timestamp must produce a filename");
        assert_eq!(&buffer[..length_written], b"chess_game_log_1778532301.txt");
    }

    #[test]
    fn game_log_filename_for_max_u64_timestamp() {
        let mut buffer: [u8; MAX_GAME_LOG_FILENAME_BYTES] = [0; MAX_GAME_LOG_FILENAME_BYTES];
        let length_written = build_game_log_filename_into_buffer(u64::MAX, &mut buffer)
            .expect("max u64 timestamp must fit in the buffer");
        assert_eq!(
            &buffer[..length_written],
            b"chess_game_log_18446744073709551615.txt"
        );
    }

    #[test]
    fn game_log_filename_returns_none_when_buffer_too_small() {
        // A 10-byte buffer cannot hold the 20-byte minimum
        // ("chess_game_log_0.txt" is 20 bytes).
        let mut too_small_buffer: [u8; 10] = [0; 10];
        let result = build_game_log_filename_into_buffer(0, &mut too_small_buffer);
        assert!(result.is_none(), "buffer too small must return None");
    }

    #[test]
    fn game_log_filename_starts_with_prefix() {
        let mut buffer: [u8; MAX_GAME_LOG_FILENAME_BYTES] = [0; MAX_GAME_LOG_FILENAME_BYTES];
        let length_written = build_game_log_filename_into_buffer(42, &mut buffer)
            .expect("test timestamp must build");
        let bytes_written = &buffer[..length_written];
        assert!(bytes_written.starts_with(GAME_LOG_FILENAME_PREFIX));
    }

    #[test]
    fn game_log_filename_ends_with_suffix() {
        let mut buffer: [u8; MAX_GAME_LOG_FILENAME_BYTES] = [0; MAX_GAME_LOG_FILENAME_BYTES];
        let length_written = build_game_log_filename_into_buffer(42, &mut buffer)
            .expect("test timestamp must build");
        let bytes_written = &buffer[..length_written];
        assert!(bytes_written.ends_with(GAME_LOG_FILENAME_SUFFIX));
    }

    // -- Terminal write tests --
    //
    // write_one_line_to_terminal_via_buffy_best_effort writes to
    // stdout. We cannot meaningfully capture stdout in a unit test
    // without process-level redirection, which adds infrastructure
    // disproportionate to the value. The only properties we can
    // verify by-construction here are:
    //   (a) the function does not panic on any input,
    //   (b) the function returns nothing (so cannot propagate error).
    //
    // The behavioral verification of "the right bytes reach stdout"
    // is left to integration testing (running the demo main and
    // observing output).

    #[test]
    fn terminal_write_does_not_panic_on_empty_input() {
        write_one_line_to_terminal_via_buffy_best_effort(b"");
        // If we reach this point, no panic occurred.
    }

    #[test]
    fn terminal_write_does_not_panic_on_ascii_input() {
        write_one_line_to_terminal_via_buffy_best_effort(b"hello world");
    }

    #[test]
    fn terminal_write_does_not_panic_on_non_utf8_input() {
        let non_utf8_bytes: [u8; 4] = [0xff, 0xfe, 0xfd, 0xfc];
        write_one_line_to_terminal_via_buffy_best_effort(&non_utf8_bytes);
    }

    // -- Log append tests --
    //
    // append_one_line_to_game_log_file_best_effort touches the file
    // system. We verify it does not panic on the failure paths (bad
    // directory, etc.) and that on a writable temp directory it
    // produces the expected file content. The latter uses
    // std::env::temp_dir() and cleans up afterward.

    #[test]
    fn log_append_does_not_panic_when_directory_does_not_exist() {
        let nonexistent_directory =
            Path::new("/this/path/should/not/exist/anywhere/on/the/test/host");
        append_one_line_to_game_log_file_best_effort(nonexistent_directory, 42, b"any content");
        // If we reach this point, no panic occurred.
    }

    #[test]
    fn log_append_writes_expected_bytes_to_writable_directory() {
        // Build a unique subdirectory inside the system temp dir.
        let mut test_directory = std::env::temp_dir();
        test_directory.push(format!("memo_chess_section63_test_{}", std::process::id()));

        // Ensure it exists, ignoring "already exists" outcomes.
        let _ = std::fs::create_dir_all(&test_directory);

        // Choose a distinctive timestamp so each test run uses a
        // unique log file name.
        let test_timestamp: u64 = 9_999_999_999;

        // First append.
        append_one_line_to_game_log_file_best_effort(
            &test_directory,
            test_timestamp,
            b"line one of two",
        );

        // Second append (same call should re-open in append mode).
        append_one_line_to_game_log_file_best_effort(
            &test_directory,
            test_timestamp,
            b"line two of two",
        );

        // Read back the log file.
        let mut expected_log_filename_buffer: [u8; MAX_GAME_LOG_FILENAME_BYTES] =
            [0; MAX_GAME_LOG_FILENAME_BYTES];
        let expected_log_filename_length =
            build_game_log_filename_into_buffer(test_timestamp, &mut expected_log_filename_buffer)
                .expect("filename must build");
        let expected_log_filename_str =
            core::str::from_utf8(&expected_log_filename_buffer[..expected_log_filename_length])
                .expect("filename must be utf-8");
        let log_file_path = test_directory.join(expected_log_filename_str);

        let contents = std::fs::read(&log_file_path).expect("log file must be readable");
        assert_eq!(contents, b"line one of two\nline two of two\n");

        // Cleanup.
        let _ = std::fs::remove_file(&log_file_path);
        let _ = std::fs::remove_dir(&test_directory);
    }
}

// ============================================================================
// SECTION 64: Outer Wrapper — run_memochess_dungeon_master_loop
// ============================================================================
//
// ## Project Context
//
// This is the top-level game-loop wrapper. It is called once by
// `main.rs` (or any other caller) after `q_and_a_setup_bootstrap`
// has produced a finalized `MemochessGameConfig` and
// `create_initial_dungeon_master_state` has produced the initial
// `DungeonMasterState`.
//
// The wrapper drives the per-tick cycle:
//
//   1. Sample the current Unix timestamp.
//   2. Call `run_one_dungeon_master_tick` to advance the state.
//   3. Handle the tick outcome:
//        - NoChange / MoveApplied / PlayerResigned / TimeFlagged:
//          accept the new state.
//        - ChronoSequenceReordered: discard the state and reset to
//          the initial state. The next iteration's tick will start
//          replaying from chrono position 0.
//        - ChronoIndexUnreadable: keep the existing state; retry
//          next tick.
//   4. Write the new state to terminal + log via the double-publish
//      closure.
//   5. If the game has ended, exit the loop and return.
//   6. Sleep `refresh_rate_seconds` and repeat.
//
// ## End-of-game detection
//
// The loop terminates when `state.board.game_status` is anything
// other than `GameStatus::StillPlaying` after a tick. The final
// state is written one more time so the user sees the end-of-game
// `Status:` line, then the wrapper returns.
//
// The wrapper does not poll for further memos after the game ends.
// If a player writes a memo after checkmate, that memo is ignored
// until the next process invocation re-bootstraps.
//
// ## Replay recovery (visible to user)
//
// On `TickOutcome::ChronoSequenceReordered`, the wrapper resets the
// state via `create_initial_dungeon_master_state(state.config)` and
// continues the main loop. The next tick will read chrono position 0,
// the tick after that position 1, and so on, with each replayed
// move being rendered and appended to the log at the configured
// `refresh_rate_seconds` cadence. This is by project design: the
// user sees the recovery happening, and the log records the full
// replay history.
//
// ## Initial render before loop entry
//
// Before entering the main loop, the wrapper writes the initial
// state once so the user sees the starting board immediately rather
// than waiting `refresh_rate_seconds` for the first tick.
//
// ## Memory & Panic Policy
//
// No heap allocation by the wrapper itself (per-tick stack copies
// of `DungeonMasterState` are bounded and small). Components called
// by the wrapper have their own documented memory policies.
//
// No panics. Every component called by the wrapper has best-effort
// or `Result`-returning semantics; any failure is surfaced through
// `TickOutcome` and handled by the loop without halting.
//
// ## No cargo tests in this section
//
// The wrapper is a loop with sleep and stdout side effects. Unit
// testing it deterministically would require dependency injection
// of the sleep function and a mock of `run_one_dungeon_master_tick`,
// which is infrastructure disproportionate to the value. Correctness
// comes from the correctness of the wrapper's components (each
// individually tested) plus integration testing via the demo
// `main.rs`.

// ----------------------------------------------------------------------------
// Internal helper: build the absolute log directory path (best effort)
// ----------------------------------------------------------------------------

/// Convert the `memo_chess_log_directory_path_as_bytes()` from the
/// game config into a `&Path` for use in log appends.
///
/// On non-UTF-8 path bytes (which the bootstrap rejected at config
/// construction time and so should not occur here), returns an
/// empty `&Path` so the log-append helper's directory-missing path
/// degrades to a no-op silently. The terminal half of the
/// double-publish continues to work in that degraded mode.
fn read_log_directory_path_str_from_config(config: &MemochessGameConfig) -> &str {
    match core::str::from_utf8(config.memo_chess_log_directory_path_as_bytes()) {
        Ok(path_str) => path_str,
        Err(_) => "",
    }
}

// ----------------------------------------------------------------------------
// Internal helper: write one full state frame to terminal AND log
// ----------------------------------------------------------------------------

/// Compose and emit one full state frame to both destinations.
///
/// This wraps `write_dungeon_master_state_to_tui_and_log` with the
/// double-publish closure: each emitted content line is sent to the
/// terminal via Buffy and appended to the game-log file.
///
/// ## Failure modes
///
/// Both halves of the double-publish are best-effort. Terminal
/// failures (closed stdout, etc.) are silently dropped by Buffy.
/// Log failures (path issue, disk full) are silently dropped by
/// `append_one_line_to_game_log_file_best_effort`. The game
/// continues in either case.
///
/// ## Memory & Panic Policy
///
/// No heap allocation inside this helper itself. The closure
/// captures references to stack-resident path values and the
/// bootstrap timestamp. The log-append helper performs one bounded
/// `PathBuf::join` per content line; this is per-call, not per-tick,
/// and is freed before the next line is emitted.
fn write_one_full_frame_to_terminal_and_log(
    state: &DungeonMasterState,
    current_unix_timestamp_seconds: u64,
) {
    let log_directory_path_str = read_log_directory_path_str_from_config(&state.config);
    let log_directory_path = std::path::Path::new(log_directory_path_str);
    let bootstrap_run_timestamp_seconds = state.config.bootstrap_run_unix_timestamp_seconds();

    let mut emit_line_closure = |line_bytes: &[u8]| {
        // Terminal half:
        write_one_line_to_terminal_via_buffy_best_effort(line_bytes);
        // Log-file half:
        append_one_line_to_game_log_file_best_effort(
            log_directory_path,
            bootstrap_run_timestamp_seconds,
            line_bytes,
        );
    };

    write_dungeon_master_state_to_tui_and_log(
        state,
        current_unix_timestamp_seconds,
        &mut emit_line_closure,
    );
}

// ----------------------------------------------------------------------------
// Public entry point: the wrapper loop
// ----------------------------------------------------------------------------

/// Run the dungeon-master game loop until the game ends, returning
/// the final `DungeonMasterState`.
///
/// ## Project Context
///
/// Called by `main.rs` (or any other top-level driver) after
/// bootstrap has finished and an initial state has been constructed.
/// Drives the per-tick cycle until `board.game_status` becomes
/// decisive (anything other than `GameStatus::StillPlaying`).
///
/// ## Replay recovery
///
/// On `TickOutcome::ChronoSequenceReordered`, the state is reset via
/// `create_initial_dungeon_master_state(state.config)` and the loop
/// continues. Each subsequent tick replays one chronological
/// position. The user sees the replay happen at the configured
/// `refresh_rate_seconds` cadence and the log captures the full
/// replay history. This is by project design.
///
/// ## Arguments
///
/// - `initial_state`: the starting `DungeonMasterState`, typically
///   produced by `create_initial_dungeon_master_state` immediately
///   after bootstrap.
///
/// ## Returns
///
/// The final `DungeonMasterState` when the game has ended. The
/// caller may inspect `final_state.board.game_status` to determine
/// the outcome.
///
/// ## Memory & Panic Policy
///
/// Heap: one `PathBuf::join` per content line per tick (bounded,
/// freed before the next line), allocated inside
/// `append_one_line_to_game_log_file_best_effort`. No heap touch
/// scales with game length.
///
/// Panic: none. Every called function is best-effort or returns
/// `Result`; no `unwrap`/`expect`/`assert!` in this function or any
/// it calls (in production code paths).
pub fn run_memochess_dungeon_master_loop(initial_state: DungeonMasterState) -> DungeonMasterState {
    let mut current_state: DungeonMasterState = initial_state;

    // Initial render before loop entry, so the user sees the starting
    // board immediately rather than waiting `refresh_rate_seconds`
    // for the first tick.
    let initial_unix_timestamp_seconds = read_current_unix_timestamp_seconds_best_effort();
    write_one_full_frame_to_terminal_and_log(&current_state, initial_unix_timestamp_seconds);

    // Main loop. Bounded only by the game ending (one of the
    // decisive `GameStatus` variants). Per NASA P10 rule 2 this is
    // an "always-loop" — the termination is event-driven (game ends)
    // rather than counter-driven. The failsafe is that every tick
    // outcome that could keep the loop running forever (e.g.,
    // `ChronoIndexUnreadable`) sleeps the configured refresh
    // interval, so the loop cannot busy-spin even under sustained
    // I/O failure.
    loop {
        // 1. Sleep before each subsequent tick, including before the
        //    very first tick after the initial render. This gives
        //    the user `refresh_rate_seconds` to look at the rendered
        //    board before the first poll cycle.
        let refresh_rate_seconds_u64: u64 = current_state.config.refresh_rate_seconds as u64;
        std::thread::sleep(std::time::Duration::from_secs(refresh_rate_seconds_u64));

        // 2. Sample current Unix timestamp once per tick. Passed to
        //    both the tick function (for live time-flag detection)
        //    and the renderer (for live clock display).
        let current_unix_timestamp_seconds = read_current_unix_timestamp_seconds_best_effort();

        // 3. Advance the state by one tick.
        let tick_result: TickResult =
            run_one_dungeon_master_tick(&current_state, current_unix_timestamp_seconds);

        // 4. Handle the tick outcome.
        match tick_result.outcome {
            TickOutcome::NoChange
            | TickOutcome::MoveApplied
            | TickOutcome::PlayerResigned
            | TickOutcome::TimeFlagged => {
                // Normal outcomes: accept the new state.
                current_state = tick_result.new_state;
            }
            TickOutcome::ChronoSequenceReordered => {
                // Recovery: discard the current state and start over
                // from the initial state. The next iteration's tick
                // will read chrono position 0 and replay forward.
                // Keep the original config (it is unchanged by gameplay).
                current_state = create_initial_dungeon_master_state(current_state.config);
            }
            TickOutcome::ChronoIndexUnreadable => {
                // Defensive: the chrono-index could not be read this
                // tick. Keep the existing state (tick_result.new_state
                // is the unchanged input state in this case). Retry
                // next tick.
                current_state = tick_result.new_state;
            }
        }

        // 5. Write the state to terminal + log.
        write_one_full_frame_to_terminal_and_log(&current_state, current_unix_timestamp_seconds);

        // 6. End-of-game check. If the board reports anything other
        //    than StillPlaying, the game is over. The final state has
        //    just been rendered in step 5, so the user has seen it.
        if current_state.board.game_status != GameStatus::StillPlaying {
            return current_state;
        }
    }
}

// ============================================================================
// SECTION 65: Move-Replay Bootstrap — replay_existing_moves_from_chrono_index
// ============================================================================
//
// ## Project Context
//
// When the dungeon-master process starts, the memo directory may
// already contain move files from a game in progress (e.g., the
// process was restarted, or the user launched the TUI after both
// players have already exchanged several moves via file sync).
//
// The config-bootstrap (`q_and_a_setup_bootstrap`, Section 59) reads
// only configuration memos. It does not process moves. The live game
// loop (`run_memochess_dungeon_master_loop`, Section 64) processes
// one move per `refresh_rate_seconds` tick — far too slow to replay
// 20+ historical moves at startup.
//
// This function bridges the gap. It is called once, between bootstrap
// and the live loop, and replays all existing moves as fast as the
// CPU allows, with no sleeps and no wall-clock involvement in time
// calculations. Move timestamps come exclusively from the TOML
// `updated_at_timestamp` field of each memo file.
//
// ## Relationship to `run_one_dungeon_master_tick`
//
// This function reuses the same per-position classification
// (`classify_chrono_position_for_player`) and move-resolution
// pipeline (`resolve_parsed_move_to_legal_chess_move`,
// `apply_chess_move_to_state`,
// `process_move_timestamp_for_game_time`) that the live tick uses.
// It does NOT call `run_one_dungeon_master_tick` itself, because
// the tick function also performs chrono-hash checks and live
// time-flag checks that are irrelevant during historical replay.
//
// ## What this function does
//
//   1. Refreshes the chrono-index against the live directory.
//   2. Reads the committed file count.
//   3. Iterates through chrono positions 0..file_count, alternating
//      between the player whose turn it is (`state.board.side_to_move`).
//   4. For each position, classifies it via
//      `classify_chrono_position_for_player`.
//   5. On finding a move candidate:
//        a. Resolves notation against the current board.
//        b. If legal: applies the move, charges game time from the
//           TOML timestamp, advances the cursor.
//        c. If illegal: advances the cursor past this file (same
//           forward-progress rule as the live loop).
//   6. On finding a resignation: ends the game.
//   7. On skip-and-continue: advances the cursor.
//   8. Stops when:
//        - The game ends (checkmate, stalemate, resignation, or
//          time flag detected from TOML timestamps alone).
//        - Both player cursors have reached the end of the
//          chrono-index without finding further moves.
//
// ## Time accounting during replay
//
// `process_move_timestamp_for_game_time` is called with the TOML
// file's `updated_at_unix_timestamp` — never with wall-clock time.
// This means the reconstructed `GameTimeState` reflects the same
// cumulative thinking times that the live loop would have computed
// had it been running continuously. Pre-moves (files whose timestamp
// is earlier than the last processed move's timestamp) are handled
// by the existing pre-move logic in
// `process_move_timestamp_for_game_time` (zero time charged).
//
// ## Chrono-hash initialization
//
// After replay completes, the function computes the chrono-sort hash
// over positions `[0, file_count)` and stores it in
// `state.last_known_chrono_hash_through_n`. This seeds the live
// loop's per-tick anomaly detection.
//
// ## N-move rule check during replay
//
// After each applied move, the function checks whether
// `state.board.halfmove_clock` has reached or exceeded
// `state.config.n_move_rule`. If so, it sets
// `state.board.game_status = GameStatus::DrawForcedNmoveRule` and
// stops replaying.
//
// ## Memory & Panic Policy
//
// No panics. No heap allocation beyond what the chrono-index module
// uses internally (bounded, documented in that module). Per-position
// work uses one `[u8; MAX_FULL_PATH_LEN]` stack buffer (inside
// `classify_chrono_position_for_player`). The function processes
// at most `MAX_GAME_FILES_FOR_BOOTSTRAP_SCAN` positions total.

/// Replay all existing moves from the chrono-index into the
/// dungeon-master state, returning the state advanced to the
/// current board position.
///
/// ## Arguments
///
/// - `initial_state`: the starting `DungeonMasterState` as produced
///   by `create_initial_dungeon_master_state`. Board is at the
///   standard starting position, game time is zero, cursors are at
///   position 0.
///
/// ## Returns
///
/// The `DungeonMasterState` after all existing moves have been
/// replayed. If no move files exist, the returned state is
/// identical to `initial_state` except that
/// `last_known_chrono_hash_through_n` and `last_known_file_count`
/// are populated.
///
/// On chrono-index failure (cannot update or read the index), the
/// function returns `initial_state` unchanged. The live loop's
/// first tick will retry the index and either succeed or return
/// `ChronoIndexUnreadable`.
pub fn replay_existing_moves_from_chrono_index(
    initial_state: DungeonMasterState,
) -> DungeonMasterState {
    let mut state: DungeonMasterState = initial_state;

    // ---- Step 1: refresh the chrono-index ----
    let chrono_temp_path =
        match core::str::from_utf8(state.config.chrono_sort_temp_directory_path_as_bytes()) {
            Ok(valid_str) => valid_str,
            Err(_) => return state,
        };
    let chrono_temp_dir: &Path = Path::new(chrono_temp_path);

    let game_files_path =
        match core::str::from_utf8(state.config.memo_toml_files_directory_path_as_bytes()) {
            Ok(valid_str) => valid_str,
            Err(_) => return state,
        };
    let game_files_dir: &Path = Path::new(game_files_path);

    // Update the chrono-index to reflect the current directory contents.
    if create_or_update_chrono_index(chrono_temp_dir, game_files_dir).is_err() {
        return state;
    }

    // ---- Step 2: read the committed file count ----
    let committed_file_count: u64 = match count_committed_files(chrono_temp_dir) {
        Ok(count) => count,
        Err(_) => return state,
    };

    // Apply the scan upper bound per project constant.
    let scan_upper_bound: u64 = if committed_file_count > MAX_GAME_FILES_FOR_BOOTSTRAP_SCAN {
        MAX_GAME_FILES_FOR_BOOTSTRAP_SCAN
    } else {
        committed_file_count
    };

    // If the directory is empty, seed the chrono-hash state and return.
    if scan_upper_bound == 0 {
        state.last_known_file_count = committed_file_count;
        // No positions to hash; leave last_known_chrono_hash_through_n
        // as None. The live loop will compute it when files appear.
        return state;
    }

    // ---- Step 3: replay loop ----
    //
    // Strategy: advance through chrono positions. For each position,
    // classify it for the player whose turn it currently is
    // (state.board.side_to_move). If the file belongs to the other
    // player or is otherwise irrelevant, advance the current
    // player's cursor past it. If it is a move for the current
    // player, resolve and apply. If it is a resignation, end.
    //
    // Both cursors advance independently. A file that belongs to
    // the wrong player for this turn still advances that player's
    // cursor (they pre-moved, but the pre-move is only consumable
    // when it is their turn). However, we must also check the
    // other player's files at each position to advance their cursor
    // past config/non-move files.
    //
    // Simpler approach for replay: scan ALL positions in order.
    // For each position, check if it is a move for the current
    // side_to_move. If yes, process it. If no (wrong player,
    // config file, malformed, etc.), skip. The per-player cursors
    // are set at the end to the position after the last file
    // examined, which is correct because the live loop should not
    // re-examine any file the replay already saw.
    //
    // Bounded loop: at most scan_upper_bound iterations.

    let mut chrono_position: u64 = 0;

    // Failsafe iteration counter per NASA P10 rule 2.
    // Maximum iterations equals scan_upper_bound (each iteration
    // processes exactly one chrono position). We add a small margin
    // for defensive comfort.
    let failsafe_max_iterations: u64 = scan_upper_bound.saturating_add(1);
    let mut iteration_count: u64 = 0;

    while chrono_position < scan_upper_bound {
        // Failsafe check.
        iteration_count = iteration_count.saturating_add(1);
        if iteration_count > failsafe_max_iterations {
            break;
        }

        // If the game has already ended (checkmate, stalemate from
        // a prior applied move, or time flag from timestamp
        // accounting), stop replaying.
        if state.board.game_status != GameStatus::StillPlaying {
            break;
        }

        // Determine whose turn it is.
        let current_side: PieceColor = state.board.side_to_move;

        // Classify this position for the current side to move.
        let classification: ScanPositionClassification = classify_chrono_position_for_player(
            chrono_temp_dir,
            chrono_position,
            current_side,
            &state.config,
        );

        match classification {
            ScanPositionClassification::SkipAndContinue => {
                // This file is not a move for the current player.
                // Advance past it.
                chrono_position = chrono_position.saturating_add(1);
            }

            ScanPositionClassification::FoundMoveCandidate {
                parsed_notation,
                move_unix_timestamp,
            } => {
                // Attempt to resolve the notation against the
                // current board.
                let resolve_result =
                    resolve_parsed_move_to_legal_chess_move(&state.board, &parsed_notation);

                match resolve_result {
                    Ok(legal_chess_move) => {
                        // Apply the move to the board.
                        let apply_result =
                            apply_chess_move_to_state(&state.board, &legal_chess_move);

                        match apply_result {
                            Ok(new_board) => {
                                // // Charge game time using the TOML
                                // // file's timestamp — NOT wall clock.
                                // process_move_timestamp_for_game_time(
                                //     &mut state.game_time_state,
                                //     current_side,
                                //     move_unix_timestamp,
                                // );

                                // Charge game time using the TOML file's timestamp.
                                process_move_timestamp_for_game_time(
                                    &mut state.game_time_state,
                                    current_side,
                                    move_unix_timestamp,
                                );

                                // === DEBUG PRINT ===
                                let side_str = match current_side {
                                    PieceColor::White => "W",
                                    PieceColor::Black => "B",
                                };
                                let _ = buffy_println(
                                    "REPLAY move: side={} ts={} W_cum={} B_cum={} last_ts={:?}",
                                    &[
                                        BuffyFormatArg::Str(side_str),
                                        BuffyFormatArg::Usize(move_unix_timestamp as usize),
                                        BuffyFormatArg::Usize(
                                            state.game_time_state.white_cumulative_seconds as usize,
                                        ),
                                        BuffyFormatArg::Usize(
                                            state.game_time_state.black_cumulative_seconds as usize,
                                        ),
                                        // Can't print Option<u64> easily, but check if last_ts is Some
                                    ],
                                );
                                // === END DEBUG PRINT ===

                                // Check for time flag from the
                                // timestamp-based charge. Use the
                                // move's own timestamp as "now" so
                                // no wall-clock leaks in.
                                let _flag_check = check_for_time_flag(
                                    &mut state.game_time_state,
                                    &new_board,
                                    move_unix_timestamp,
                                );

                                // Apply time flag to board status
                                // if one was just detected.
                                let status_updated_board =
                                    apply_timeflag_to_game_status(new_board, state.game_time_state);

                                // Check N-move rule.
                                let final_board = if status_updated_board.game_status
                                    == GameStatus::StillPlaying
                                {
                                    // halfmove_clock is in
                                    // half-moves; n_move_rule is
                                    // also in half-moves per
                                    // project spec.
                                    if status_updated_board.halfmove_clock as u16
                                        >= state.config.n_move_rule
                                    {
                                        let mut drawn_board = status_updated_board;
                                        drawn_board.game_status = GameStatus::DrawForcedNmoveRule;
                                        drawn_board
                                    } else {
                                        status_updated_board
                                    }
                                } else {
                                    status_updated_board
                                };

                                state.board = final_board;
                            }
                            Err(_) => {
                                // apply_chess_move_to_state failed
                                // (internal error). Skip this move
                                // per forward-progress rule.
                            }
                        }
                    }
                    Err(_) => {
                        // Illegal or ambiguous notation. Skip per
                        // forward-progress rule.
                    }
                }

                // Advance past this position regardless of whether
                // the move was legal.
                chrono_position = chrono_position.saturating_add(1);
            }

            ScanPositionClassification::FoundResignationCommand {
                command_unix_timestamp,
            } => {
                // Process time charge for the resignation.
                process_non_move_command_timestamp_for_game_time(
                    &mut state.game_time_state,
                    &state.board,
                    command_unix_timestamp,
                );

                // Set game status based on who resigned.
                let resignation_status: GameStatus = match current_side {
                    PieceColor::White => GameStatus::WhiteResigned,
                    PieceColor::Black => GameStatus::BlackResigned,
                };
                state.board.game_status = resignation_status;

                chrono_position = chrono_position.saturating_add(1);
                // Game has ended; the while-loop condition check at
                // the top will break on the next iteration.
            }
        }
    }

    // ---- Step 4: set cursors for the live loop ----
    //
    // Both cursors advance to `chrono_position` (the position after
    // the last file examined). The live loop starts scanning from
    // here for both players. This prevents re-examining any file
    // that the replay already classified.
    state.white_next_file_chronoindex_to_check = chrono_position;
    state.black_next_file_chronoindex_to_check = chrono_position;

    // ---- Step 5: seed the chrono-hash for anomaly detection ----
    state.last_known_file_count = committed_file_count;

    if committed_file_count > 0 {
        // Compute the order-sensitive hash over [0, committed_file_count - 1].
        match chrono_sort_hash_to_n(chrono_temp_dir, committed_file_count - 1) {
            Ok(hash_value) => {
                state.last_known_chrono_hash_through_n = Some(hash_value);
            }
            Err(_) => {
                // Failed to compute hash. Leave as None; the live
                // loop will recompute or rebuild defensively.
            }
        }
    }

    // ---- Step 6: anchor the live clock reference to wall-clock now ----
    //
    // During replay, `last_normal_move_unix_timestamp` was set to the
    // TOML timestamp of the last replayed move. This is correct for
    // computing cumulative time between historical moves. But the
    // live display function (`compute_player_time_remaining_seconds`)
    // computes:
    //
    //   live_elapsed = wall_clock_now - last_normal_move_unix_timestamp
    //
    // If the process was not running between the last historical move
    // and now (e.g., the TUI was restarted, or a long pause occurred),
    // that gap would be incorrectly charged to the player currently
    // on the clock.
    //
    // By resetting `last_normal_move_unix_timestamp` to wall-clock
    // "now" at the end of replay, the live-elapsed counter starts
    // from zero at process startup. The cumulative totals already
    // contain all historical thinking time; only NEW thinking time
    // (from this moment forward) should appear as live elapsed.
    //
    // If no moves were replayed (`last_normal_move_unix_timestamp`
    // is still `None`), no adjustment is needed — the display
    // function already returns `max_time_per_player_seconds` when
    // no reference timestamp exists.
    if state
        .game_time_state
        .last_normal_move_unix_timestamp
        .is_some()
    {
        let now_seconds: u64 = read_current_unix_timestamp_seconds_best_effort();
        state.game_time_state.last_normal_move_unix_timestamp = Some(now_seconds);
    }

    state
}
